namespace :backup do
  desc "Generate a backup archive using tar"
  task :create, [:name, :path] => :environment do |task, args|
    name = args.name || "backup"
    path = args.path || Dir.pwd
    
    %x[tar -czf #{name}.tar.gz -C #{path} .]
    
    puts "Backup created: #{name}.tar.gz"
  end
end